import logging
import json
import os
from datetime import datetime
import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.core.messaging import CloudEvent

app = func.FunctionApp()

# Configuration
STORAGE_ACCOUNT_URL = os.environ.get("STORAGE_ACCOUNT_URL", "https://<storage-account>.blob.core.windows.net")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT", "https://<cosmos-account>.documents.azure.com:443/")
COSMOS_DATABASE_NAME = os.environ.get("COSMOS_DATABASE_NAME", "ProcessedData")
COSMOS_CONTAINER_NAME = os.environ.get("COSMOS_CONTAINER_NAME", "Results")
EVENT_GRID_ENDPOINT = os.environ.get("EVENT_GRID_ENDPOINT", "https://<topic-name>.<region>.eventgrid.azure.net/api/events")

# Initialize clients with Managed Identity
credential = DefaultAzureCredential()
blob_service_client = BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)
cosmos_client = CosmosClient(url=COSMOS_ENDPOINT, credential=credential)
event_grid_client = EventGridPublisherClient(EVENT_GRID_ENDPOINT, credential)

# Get or create Cosmos DB database and container
database = cosmos_client.get_database_client(COSMOS_DATABASE_NAME)
container = database.get_container_client(COSMOS_CONTAINER_NAME)

@app.blob_trigger(arg_name="myblob", path="input-files/{name}", connection="STORAGE_ACCOUNT_URL")
def process_blob(myblob: func.InputStream):
    logging.info(f"Processing blob: {myblob.name}, Size: {myblob.length} bytes")
    
    try:
        # Read and process the blob content
        blob_content = myblob.read()
        
        # Process the file (example: count lines if text, or size if binary)
        processing_result = process_file_content(blob_content, myblob.name)
        
        # Write results to Cosmos DB
        cosmos_document = {
            "id": f"{datetime.utcnow().timestamp()}_{myblob.name.replace('/', '_')}",
            "blobName": myblob.name,
            "processedAt": datetime.utcnow().isoformat(),
            "fileSize": myblob.length,
            "processingResult": processing_result,
            "status": "completed"
        }
        
        container.upsert_item(cosmos_document)
        logging.info(f"Written to Cosmos DB: {cosmos_document['id']}")
        
        # Send notification via Event Grid
        event = CloudEvent(
            type="FileProcessing.Completed",
            source=f"/blobstorage/{myblob.name}",
            data={
                "blobName": myblob.name,
                "documentId": cosmos_document['id'],
                "processedAt": cosmos_document['processedAt'],
                "status": "completed",
                "result": processing_result
            }
        )
        
        event_grid_client.send([event])
        logging.info(f"Event sent to Event Grid for blob: {myblob.name}")
        
    except Exception as e:
        logging.error(f"Error processing blob {myblob.name}: {str(e)}")
        
        # Write error to Cosmos DB
        error_document = {
            "id": f"error_{datetime.utcnow().timestamp()}_{myblob.name.replace('/', '_')}",
            "blobName": myblob.name,
            "processedAt": datetime.utcnow().isoformat(),
            "status": "failed",
            "error": str(e)
        }
        
        try:
            container.upsert_item(error_document)
            
            # Send error notification
            error_event = CloudEvent(
                type="FileProcessing.Failed",
                source=f"/blobstorage/{myblob.name}",
                data={
                    "blobName": myblob.name,
                    "error": str(e),
                    "processedAt": error_document['processedAt'],
                    "status": "failed"
                }
            )
            
            event_grid_client.send([error_event])
            
        except Exception as nested_error:
            logging.error(f"Failed to log error: {str(nested_error)}")
        
        raise

def process_file_content(content: bytes, filename: str) -> dict:
    """
    Process file content based on type
    Returns processing results as a dictionary
    """
    result = {
        "filename": filename,
        "size_bytes": len(content)
    }
    
    # Try to process as text
    try:
        text_content = content.decode('utf-8')
        lines = text_content.split('\n')
        result["line_count"] = len(lines)
        result["character_count"] = len(text_content)
        result["word_count"] = len(text_content.split())
        result["content_type"] = "text"
    except UnicodeDecodeError:
        # Binary file
        result["content_type"] = "binary"
        result["description"] = "Binary file processed"
    
    return result

@app.route(route="health", methods=["GET"])
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """Health check endpoint"""
    return func.HttpResponse(
        json.dumps({
            "status": "healthy",
            "timestamp": datetime.utcnow().isoformat(),
            "services": {
                "blob_storage": "configured",
                "cosmos_db": "configured",
                "event_grid": "configured"
            }
        }),
        mimetype="application/json",
        status_code=200
    )

@app.route(route="manual-process", methods=["POST"])
def manual_process(req: func.HttpRequest) -> func.HttpResponse:
    """Manually trigger processing of a specific blob"""
    try:
        req_body = req.get_json()
        container_name = req_body.get('containerName', 'input-files')
        blob_name = req_body.get('blobName')
        
        if not blob_name:
            return func.HttpResponse(
                json.dumps({"error": "blobName is required"}),
                mimetype="application/json",
                status_code=400
            )
        
        # Get blob content
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)
        blob_content = blob_client.download_blob().readall()
        
        # Process
        processing_result = process_file_content(blob_content, blob_name)
        
        # Write to Cosmos DB
        cosmos_document = {
            "id": f"manual_{datetime.utcnow().timestamp()}_{blob_name.replace('/', '_')}",
            "blobName": blob_name,
            "processedAt": datetime.utcnow().isoformat(),
            "fileSize": len(blob_content),
            "processingResult": processing_result,
            "status": "completed",
            "triggerType": "manual"
        }
        
        container.upsert_item(cosmos_document)
        
        # Send Event Grid notification
        event = CloudEvent(
            type="FileProcessing.ManuallyCompleted",
            source=f"/blobstorage/{blob_name}",
            data={
                "blobName": blob_name,
                "documentId": cosmos_document['id'],
                "processedAt": cosmos_document['processedAt'],
                "status": "completed"
            }
        )
        
        event_grid_client.send([event])
        
        return func.HttpResponse(
            json.dumps({
                "success": True,
                "documentId": cosmos_document['id'],
                "result": processing_result
            }),
            mimetype="application/json",
            status_code=200
        )
        
    except Exception as e:
        logging.error(f"Error in manual processing: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": str(e)}),
            mimetype="application/json",
            status_code=500
        )

@app.route(route="query-results", methods=["GET"])
def query_results(req: func.HttpRequest) -> func.HttpResponse:
    """Query processed results from Cosmos DB"""
    try:
        status = req.params.get('status', 'completed')
        limit = int(req.params.get('limit', '10'))
        
        query = f"SELECT TOP {limit} * FROM c WHERE c.status = @status ORDER BY c.processedAt DESC"
        items = list(container.query_items(
            query=query,
            parameters=[{"name": "@status", "value": status}],
            enable_cross_partition_query=True
        ))
        
        return func.HttpResponse(
            json.dumps({
                "count": len(items),
                "items": items
            }),
            mimetype="application/json",
            status_code=200
        )
        
    except Exception as e:
        logging.error(f"Error querying results: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": str(e)}),
            mimetype="application/json",
            status_code=500
        )